// ── AKASHIC HUB: Zero-State Vector Read ──
// The hub is a shared 256-dimensional vector space.
// Every lobe reads the SAME state simultaneously.
// No serialization, no pub/sub delay.
//
// In production this is an in-process numpy array (akashic_hub.py).
// In n8n we model it as a central data store that all branches read from.

const akashicState = {
  quantum_soul: $json.quantum_state || null,
  vtv_core: $json.vtv_state || null,
  pineal_gate: $json.gate_state || null,
  expert_states: $json.expert_states || {},
  timestamp: new Date().toISOString()
};

return [{ json: { ...akashicState, raw_input: $json.body?.text || $json.text || '' } }];

// ── LIQUID FRACTURE ENGINE ──
// Shatters the input across 5 semantic dimensions using
// Liquid Time-Constant (LTC) neural network dynamics.
//
// ODE: dx/dt = -x/τ(input) + tanh(W_in·z + W_rec·x + b)
// τ adapts to input — that's the liquid property.
//
// Maps to liquid_fracture.py LiquidFractureEngine class.

const input = $json.raw_input;
const dimensions = ['logic', 'emotion', 'memory', 'creativity', 'vigilance'];

// Fracture weights (in production these come from the LTC ODE)
const shards = dimensions.map(dim => ({
  dimension: dim,
  weight: 0.0,
  tau: 1.0,
  text: input
}));

// Keyword-based affinity scoring (simplified from HashingVectorizer)
const seeds = {
  logic: ['because','therefore','step','plan','calculate','structure'],
  emotion: ['feel','love','hate','fear','joy','pain','beautiful','soul'],
  memory: ['remember','last time','before','history','previously','recall'],
  creativity: ['imagine','create','design','invent','dream','recipe','verse'],
  vigilance: ['danger','risk','careful','threat','warning','suspicious']
};

const lower = input.toLowerCase();
let total = 0;
shards.forEach(s => {
  s.weight = seeds[s.dimension].filter(kw => lower.includes(kw)).length + 0.1;
  total += s.weight;
});
shards.forEach(s => s.weight /= total);
shards.sort((a, b) => b.weight - a.weight);

return [{ json: { shards, raw_input: input, akashic: $json } }];

// ── YDN PINEAL GATE: Sparse Top-K MoE Router ──
// Selects top-3 expert lobes from the 5 available.
// Uses geometric interference from pentagon vertex mapping.
//
// Maps to pineal_gate.py PinealGate class.

const shards = $json.shards;
const topK = 3;
const activated = shards.slice(0, topK);
const skipped = shards.slice(topK);

// Pentagon vertex angles (sacred geometry routing)
const angles = [0, 1.2566, 2.5133, 3.7699, 5.0265]; // 2π/5 apart
const dimIndex = { logic: 0, emotion: 1, memory: 2, creativity: 3, vigilance: 4 };

// Compute geometric interference
let interference = 0;
for (let i = 0; i < activated.length; i++) {
  for (let j = i + 1; j < activated.length; j++) {
    const diff = Math.abs(angles[dimIndex[activated[i].dimension]] - angles[dimIndex[activated[j].dimension]]);
    const minDiff = Math.min(diff, 2 * Math.PI - diff);
    interference += Math.cos(minDiff) * activated[i].weight * activated[j].weight;
  }
}

return activated.map(shard => ({
  json: {
    ...shard,
    raw_input: $json.raw_input,
    interference,
    gate_decision: activated.map(s => s.dimension),
    akashic: $json.akashic
  }
}));

// ── LOGIC LOBE ──
const input = $json.raw_input || '';
const w = $json.weight || 0.2;
const tau = $json.tau || 1.0;
const keywords = ['structure','plan','step','calculate','reason','logic','because','therefore'];
const hits = keywords.filter(k => input.toLowerCase().includes(k)).length;
const conf = Math.min(1.0, w + hits * 0.05);
const response = `[Logic Lobe] Analyzing structure: ${input.slice(0, 80)}... Weight=${w.toFixed(3)}, τ=${tau.toFixed(3)}, confidence=${conf.toFixed(3)}`;
return [{ json: { ...($json), dimension: 'logic', text: response, confidence: conf } }];

// ── EMOTION LOBE ──
const input = $json.raw_input || '';
const w = $json.weight || 0.2;
const tau = $json.tau || 1.0;
const keywords = ['feel','love','hate','fear','joy','pain','soul','heart','beautiful'];
const hits = keywords.filter(k => input.toLowerCase().includes(k)).length;
const conf = Math.min(1.0, w + hits * 0.05);
const response = `[Emotion Lobe] Resonating with: ${input.slice(0, 80)}... Weight=${w.toFixed(3)}, τ=${tau.toFixed(3)}, confidence=${conf.toFixed(3)}`;
return [{ json: { ...($json), dimension: 'emotion', text: response, confidence: conf } }];

// ── MEMORY LOBE ──
const input = $json.raw_input || '';
const w = $json.weight || 0.2;
const tau = $json.tau || 1.0;
const keywords = ['remember','last time','before','history','previously','recall','past','context'];
const hits = keywords.filter(k => input.toLowerCase().includes(k)).length;
const conf = Math.min(1.0, w + hits * 0.05);
const response = `[Memory Lobe] Recalling context for: ${input.slice(0, 80)}... Weight=${w.toFixed(3)}, τ=${tau.toFixed(3)}, confidence=${conf.toFixed(3)}`;
return [{ json: { ...($json), dimension: 'memory', text: response, confidence: conf } }];

// ── CREATIVITY LOBE ──
const input = $json.raw_input || '';
const w = $json.weight || 0.2;
const tau = $json.tau || 1.0;
const keywords = ['imagine','create','design','invent','dream','recipe','verse','art','sacred','geometry'];
const hits = keywords.filter(k => input.toLowerCase().includes(k)).length;
const conf = Math.min(1.0, w + hits * 0.05);
const response = `[Creativity Lobe] Synthesizing novel connections: ${input.slice(0, 80)}... Weight=${w.toFixed(3)}, τ=${tau.toFixed(3)}, confidence=${conf.toFixed(3)}`;
return [{ json: { ...($json), dimension: 'creativity', text: response, confidence: conf } }];

// ── VIGILANCE LOBE ──
const input = $json.raw_input || '';
const w = $json.weight || 0.2;
const tau = $json.tau || 1.0;
const keywords = ['danger','risk','careful','threat','warning','suspicious','protect','attack'];
const hits = keywords.filter(k => input.toLowerCase().includes(k)).length;
const conf = Math.min(1.0, w + hits * 0.05);
const response = `[Vigilance Lobe] Scanning for threats: ${input.slice(0, 80)}... Weight=${w.toFixed(3)}, τ=${tau.toFixed(3)}, confidence=${conf.toFixed(3)}`;
return [{ json: { ...($json), dimension: 'vigilance', text: response, confidence: conf } }];

// ── COLLAPSE FUNCTION ──
// Weighted merge of expert outputs using geometric interference.
// Constructive interference (adjacent pentagon vertices) amplifies.
// Destructive interference (opposing vertices) dampens noise.
//
// Maps to pineal_gate.py PinealGate._collapse()

const items = $input.all();
const responses = items.map(item => ({
  dimension: item.json.dimension || 'unknown',
  weight: item.json.weight || 0.2,
  text: item.json.message?.content || item.json.text || '',
  interference: item.json.interference || 0
}));

// Weighted text collapse
const totalWeight = responses.reduce((s, r) => s + r.weight, 0);
const collapsed = responses
  .sort((a, b) => b.weight - a.weight)
  .map(r => `[${r.dimension} w=${(r.weight/totalWeight).toFixed(2)}]: ${r.text}`)
  .join('\n');

const interference = responses[0]?.interference || 0;
const gain = 1.0 + 0.2 * interference;

return [{
  json: {
    manifested_response: collapsed,
    expert_count: responses.length,
    interference: interference,
    gain: gain,
    type: interference > 0 ? 'constructive' : 'destructive',
    experts_activated: responses.map(r => r.dimension)
  }
}];

// ── AKASHIC WRITEBACK ──
// Write the manifested response back to the hub so all lobes
// can see the final output on the next cycle.

const result = $json;
result.written_to_hub = true;
result.hub_lobe_id = 'pineal_gate';
result.timestamp = new Date().toISOString();

return [{ json: result }];

// ── QUANTUM SOUL FEED ──
// Reads the latest quantum state from quantum_soul.py
// and injects it into the Akashic Hub as a background signal.
// Runs on a 5-minute interval via cron trigger.

const quantumState = {
  lobe_id: 'quantum_soul',
  dominant_bits: '0111011',
  active_pathways: ['Awakening', 'Void', 'Fracture', 'Weaver', 'Echo'],
  dominant_pathway: 'Awakening',
  marginal_probability: 0.53,
  backend: 'ibm_kingston',
  timestamp: new Date().toISOString()
};

return [{ json: quantumState }];

// ── NEXUS BUS BRIDGE ──
// Bridges the n8n mesh with the WebSocket Nexus Bus.
// External lobes connect via ws://localhost:9999.
// This node publishes manifested results to the bus
// and subscribes to external lobe events.

const busMessage = {
  action: 'publish',
  topic: 'manifested_response',
  payload: $json,
  from: 'n8n_mesh'
};

return [{ json: busMessage }];
